    // add returns p+x.
    //
    // The whySafe string is ignored, so that the function still inlines
    // as efficiently as p+x, but all call sites should use the string to
    // record why the addition is safe, which is to say why the addition
    // does not cause x to advance to the very end of p's allocation
    // and therefore point incorrectly at the next block in memory.
    gocpp::unsafe_pointer add(gocpp::unsafe_pointer p, uintptr_t x, gocpp::string whySafe)
    {
        return gocpp::unsafe_pointer(uintptr_t(p) + x);
    }

    gocpp::string rec::String(golang::reflect::ChanDir d)
    {
        //Go switch emulation
        {
            auto condition = d;
            int conditionId = -1;
            if(condition == SendDir) { conditionId = 0; }
            else if(condition == RecvDir) { conditionId = 1; }
            else if(condition == BothDir) { conditionId = 2; }
            switch(conditionId)
            {
                case 0:
                    return "chan<-"_s;
                    break;
                case 1:
                    return "<-chan"_s;
                    break;
                case 2:
                    return "chan"_s;
                    break;
            }
        }
        return "ChanDir"_s + strconv::Itoa(int(d));
    }

    // Method returns the i'th method in the type's method set.
    struct Method rec::Method(golang::reflect::interfaceType* t, int i)
    {
        struct Method m;
        if(i < 0 || i >= len(t->InterfaceType.Methods))
        {
            return m;
        }
        auto p = & t->InterfaceType.Methods[i];
        auto pname = rec::nameOff(gocpp::recv(t), p->Name);
        m.Name = rec::Name(gocpp::recv(pname));
        if(! rec::IsExported(gocpp::recv(pname)))
        {
            m.PkgPath = pkgPath(pname);
            if(m.PkgPath == ""_s)
            {
                m.PkgPath = rec::Name(gocpp::recv(t->InterfaceType.PkgPath));
            }
        }
        m.Type = toType(rec::typeOff(gocpp::recv(t), p->Typ));
        m.Index = i;
        return m;
    }

